import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a0 as a,a2 as m,a1 as d,C as o}from"./framework-a4c02b8f.js";const f={},u=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/db61e57e4e381426cf35127e6e8a4d5e.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>「真正聪明的人能让傻瓜也理解复杂的事情」这样的言论在互联网上流传已久。但近年，也有一种观点认为「这种说法其实是傻瓜对自己无法理解他人说明的开脱」。在网络讨论中，由于没有公正的评判者存在，所以永远也无法得出答案。</p><p>我自己也偶尔思考过这个问题，能够传达好某种信息的人，是因为他们对那个事物有自信满满的理解，所以可以说他们「擅长」这个。例如，我从小就喜欢『怪兽农场2』，所以如果要教一个新手玩这个游戏的话，我相对而言可以比较顺利地让他们理解。因为我对这个游戏的大部分规则都有自信的理解。但这并不意味着我能够以同样的方式教授其他游戏，所以这只是「擅长『怪兽农场2』的人」，而不是真正的「聪明人」。</p><p>然而，如果限定在能够教授数学或历史等一般知识的人，这与生活和工作直接相关，我们也会认同他们是「聪明人」。但即使是在社会上没有用处，而在游戏方面整体都非常厉害的人，他也同样是个「聪明人」。</p><p>此外，虽然个人理解能力非常高，但在指导他人方面却非常拙劣的人也是存在的。由于智商过高，所以反而不擅长与普通人沟通。毕竟，「教」这一行为也是与沟通能力这一参数有关的。所以，草率地认为「这家伙无法教别人东西，所以不是真正聪明的人」是不妥的。这只是参数设置的问题而已。</p><p>那么，真正聪明的人应该做什么呢？在我浅薄的思考中，我认为「能够为任何人指示最适合的行动的人」，相当接近「真正聪明的人」这个模糊的概念。</p><p>我们因为脑子不好，所以当挑战新事物或忙碌到头脑恐慌时，我们不知道接下来应该做什么。或者因为「找借口」而不去追逐梦想而停滞不前，就像梦想成为轻小说作家的宅男少年擅自断定「现在还不是写小说的时机」，最终不知不觉地长大了。我可以理解这种心情...。在最糟糕的情况下，会做出完全没有意义的努力。大家都害怕这个，所以很难展开行动。</p><p>这时候，一个可以瞬间判断出「总之现在先做这个，道路会一点一点开辟出来的」的人。这不是非常聪明吗？「不是非常聪明吗？」嗯，这话说得挺笨的。</p><p>真正理解力高的人会立刻想到「即使现在还不是写轻小说的时候，先练习一下构思情节吧」，或者「那就先读更多的轻小说，至少确定自己的目标方向吧」，或者「先模仿喜欢的作家的文风，将其融入自己的写作风格」之类的行动。虽然这是一个轻小说作家的极端例子，但即使是对于陌生的工作环境和人际关系，也可以灵活应用。能够快速思考出这种「回答」的人，我肯定会觉得他们很聪明。我也很向往他们。</p><p>如果是这种「能看清道路」的人，即使对于笨蛋，也可以给予建议，比如「先试着从这个任务开始做」。虽然与「能够让笨蛋理解事情的人」相似，但又有所不同。这是极致的「效率」。真酷啊。</p><p>作为开端，大家与其浪费时间阅读这样的拙劣的文章，不如多睡一分钟，这绝对会成为明天活力的源泉。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/bef40b7d7f8aacbaee1c7696d222acf9.JPG" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/e6c8ca7b1380a9af83ed2270ab06c049.JPG" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【可畏的手办】这是ALTER推出的「Formidable」的手办。非常大。从各个方面。悲伤的表情非常出色，但我也喜欢从背后散发出的「异形的神圣感」。真的很大。</p></blockquote>',14);function g(x,y){const n=o("ExternalLinkIcon"),l=o("RouterLink");return s(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第12回／「頭が良い人」なる概念について考えていること"),a(n)])]),e("blockquote",null,[k,e("p",null,[a(l,{to:"/posts/Translate/nyalra_kb_11.html"},{default:m(()=>[t("【奈亚拉面壁自语】第11回｜跟不上时事话题的夜晚【230131】")]),_:1})])]),b])}const V=c(f,[["render",g],["__file","nyalra_kb_12.html.vue"]]);export{V as default};
